     1→import { Router } from 'express';
     2→import { db } from '../db';
     3→import { cache, TTL } from '../cache';
     4→
     5→const router = Router();
     6→const USERS_KEY = 'users:all';
     7→
     8→function mapRow(row: any) {
     9→  return {
    10→    id:         row.id ? Number(row.id) : undefined,
    11→    name:       row.name,
    12→    role:       row.role,
    13→    department: row.department,
    14→  };
    15→}
    16→
    17→function dbRequired(res: any) {
    18→  return res.status(503).json({ error: 'База данных недоступна' });
    19→}
    20→
    21→// GET /api/users
    22→router.get('/', async (req, res) => {
    23→  if (!db.pool || !db.isConnected) return dbRequired(res);
    24→
    25→  const cached = cache.get<ReturnType<typeof mapRow>[]>(USERS_KEY);
    26→  if (cached) {
    27→    if (req.headers['if-none-match'] === cached.etag) return res.status(304).end();
    28→    res.setHeader('ETag', cached.etag);
    29→    res.setHeader('Cache-Control', 'private, max-age=300');
    30→    return res.json(cached.data);
    31→  }
    32→
    33→  try {
    34→    const result = await db.pool.query('SELECT * FROM marketing_users ORDER BY name ASC');
    35→    const data = result.rows.map(mapRow);
    36→    const entry = cache.set(USERS_KEY, data, TTL.USERS);
    37→    res.setHeader('ETag', entry.etag);
    38→    res.setHeader('Cache-Control', 'private, max-age=300');
    39→    return res.json(data);
    40→  } catch (err: any) {
    41→    return res.status(500).json({ error: err.message });
    42→  }
    43→});
    44→
    45→// POST /api/users
    46→router.post('/', async (req, res) => {
    47→  const { id, name, role, pin, department, originalName } = req.body;
    48→  if (!name || !role || !pin) {
    49→    return res.status(400).json({ error: 'ФИО, роль и ПИН-код обязательны' });
    50→  }
    51→  if (!db.pool || !db.isConnected) return dbRequired(res);
    52→
    53→  const dept = department || (role === 'admin' ? 'Администрация' : 'Отдел продаж');
    54→
    55→  try {
    56→    if (id) {
    57→      const client = await db.pool.connect();
    58→      try {
    59→        await client.query('BEGIN');
    60→        await client.query(
    61→          `UPDATE marketing_users SET name = $1, role = $2, pin = $3, department = $4 WHERE id = $5`,
    62→          [name, role, pin, dept, id]
    63→        );
    64→        if (originalName && originalName !== name) {
    65→          await client.query(
    66→            `UPDATE leads_reporting SET manager_name = $1 WHERE manager_name = $2`,
    67→            [name, originalName]
    68→          );
    69→          await client.query(
    70→            `UPDATE work_sessions SET manager_name = $1 WHERE manager_name = $2`,
    71→            [name, originalName]
    72→          );
    73→          cache.del('leads:all');
    74→        }
    75→        await client.query('COMMIT');
    76→      } catch (txErr) {
    77→        await client.query('ROLLBACK');
    78→        throw txErr;
    79→      } finally {
    80→        client.release();
    81→      }
    82→    } else {
    83→      await db.pool.query(
    84→        `INSERT INTO marketing_users (name, role, pin, department, bio, avatar_color)
    85→         VALUES ($1, $2, $3, $4, '', 'from-indigo-500 to-purple-600')`,
    86→        [name, role, pin, dept]
    87→      );
    88→    }
    89→    cache.del(USERS_KEY);
    90→    return res.json({ success: true, name });
    91→  } catch (err: any) {
    92→    return res.status(500).json({ error: 'Database write error: ' + err.message });
    93→  }
    94→});
    95→
    96→// DELETE /api/users/:name
    97→router.delete('/:name', async (req, res) => {
    98→  const { name } = req.params;
    99→  if (!db.pool || !db.isConnected) return dbRequired(res);
   100→  try {
   101→    await db.pool.query('DELETE FROM marketing_users WHERE name = $1', [name]);
   102→    cache.del(USERS_KEY);
   103→    return res.json({ success: true });
   104→  } catch (err: any) {
   105→    return res.status(500).json({ error: err.message });
   106→  }
   107→});
   108→
   109→export default router;
