    18→function calcSalary(showUps: number, totalDeposits: number, weightedDeposits: number, workedSecs: number, rules: CommissionRules): number {
    19→  const over      = totalDeposits > (rules.poThreshold ?? 140);
    20→  const visitRate = over ? rules.perShowUpHigh : rules.perShowUpLow;
    21→  const poRate    = over ? rules.perPoHigh     : rules.perPoLow;
    22→  return showUps * visitRate + (workedSecs / 3600) * rules.hourlyRate + weightedDeposits * poRate;
    23→}
