    25→function fmtHours(secs: number): string {
    26→  const h = Math.floor(secs / 3600);
    27→  const m = Math.floor((secs % 3600) / 60);
    28→  if (h === 0) return `${m} мин`;
    29→  return m > 0 ? `${h} ч ${m} мин` : `${h} ч`;
    30→}
