    26→  if (!raw) return '';
    27→  const parts = raw.split(' ');
    28→  const [year, month, day] = (parts[0] || '').split('-').map(Number);
    29→  const timePart = parts[1] || '';
    30→  const [hh, mm] = timePart.split(':').map(Number);
    31→  if (!year || !month || !day) return raw.slice(0, 10);
    32→  const time = timePart ? ` ${String(hh || 0).padStart(2, '0')}:${String(mm || 0).padStart(2, '0')}` : '';
    33→  return `${day} ${MONTHS[month - 1]}${time}`;
    34→}
    35→
    36→function mskDateStr(offsetDays: number): string {
    37→  const d = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Moscow' }));
    38→  d.setDate(d.getDate() + offsetDays);
    39→  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    40→}
    41→
    42→function daysAgo(raw: string): string {
    43→  const todayMsk = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Moscow' }));
    44→  todayMsk.setHours(0, 0, 0, 0);
    45→  const date = new Date(raw);
    46→  const bookDay = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
    47→  const diff = Math.floor((todayMsk.getTime() - bookDay.getTime()) / 86_400_000);
    48→  if (diff === 1) return 'вчера';
    49→  if (diff === 0) return 'сегодня';
    50→  if (diff <= 4) return `${diff} дня назад`;
    51→  return `${diff} дней назад`;
    52→}
    53→
    54→function fmtPhone(p: string): string {
    55→  if (!p) return '';
    56→  const d = p.replace(/\D/g, '');
    57→  if (d.length === 11) return `+7 (${d.slice(1,4)}) ${d.slice(4,7)}-${d.slice(7,9)}-${d.slice(9,11)}`;
    58→  return p;
    59→}
    60→
    61→function fmtMoney(n: number): string {
    62→  return n.toLocaleString('ru') + '\u00a0₽';
    63→}
    64→
    65→type YclientsFilter = 'all' | 'no_data' | 'waiting' | 'confirmed' | 'showed' | 'no_show_ycl' | 'deleted';
    66→type DepositFilter  = 'all' | 'paid' | 'not_paid' | 'no_deposit';
    67→
    68→const RECORD_STATUS: Record<string, { text: string; cls: string }> = {
    69→  booked:      { text: 'Запись',      cls: 'bg-indigo-50 text-indigo-600 border-indigo-200' },
    70→  rescheduled: { text: 'Перенос',     cls: 'bg-amber-50 text-amber-600 border-amber-200'   },
    71→  showed_up:   { text: 'Пришёл ✓',   cls: 'bg-emerald-50 text-emerald-700 border-emerald-200' },
    72→  no_show:     { text: 'Не пришёл',  cls: 'bg-rose-50 text-rose-600 border-rose-200'       },
    73→  cancelled:   { text: 'Отменено',   cls: 'bg-neutral-100 text-neutral-500 border-neutral-200' },
    74→};
    75→
    76→function yclLabel(att: number | null, deleted?: boolean | null) {
    77→  if (deleted) return { text: 'Удалено',            cls: 'text-neutral-500', dot: 'bg-neutral-400' };
    78→  switch (att) {
    79→    case  1: return { text: 'Пришёл',             cls: 'text-emerald-700', dot: 'bg-emerald-500' };
    80→    case -1: return { text: 'Не пришёл',          cls: 'text-rose-700',    dot: 'bg-rose-500'    };
    81→    case  0: return { text: 'Ожидание',           cls: 'text-amber-700',   dot: 'bg-amber-400'   };
    82→    case  2: return { text: 'Подтвердил запись',  cls: 'text-indigo-700',  dot: 'bg-indigo-500'  };
    83→    default: return { text: 'Нет данных Yclients', cls: 'text-neutral-400', dot: 'bg-neutral-300' };
    84→  }
    85→}
    86→
    87→function PillGroup<T extends string>({
    88→  value,
    89→  onChange,
    90→  options,
    91→}: {
    92→  value: T;
    93→  onChange: (v: T) => void;
    94→  options: { id: T; label: string }[];
    95→}) {
    96→  return (
    97→    <div className="flex gap-1 overflow-x-auto no-scrollbar">
    98→      {options.map(o => (
    99→        <button
   100→          key={o.id}
   101→          onClick={() => onChange(o.id)}
   102→          className={`shrink-0 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-colors duration-150 cursor-pointer whitespace-nowrap select-none border ${
   103→            value === o.id
   104→              ? 'bg-neutral-950 text-white border-neutral-950'
   105→              : 'bg-white/60 text-neutral-500 border-neutral-200/70 hover:text-neutral-800 hover:bg-white'
   106→          }`}
   107→        >
   108→          {o.label}
   109→        </button>
   110→      ))}
   111→    </div>
   112→  );
   113→}
